def _hoare_quicksort(arr, lo, hi):
    if lo >= hi:
        return
    pivot = arr[(lo + hi) // 2]
    i, j = lo, hi
    while i <= j:
        while arr[i] < pivot:
            i += 1
        while arr[j] > pivot:
            j -= 1
        if i <= j:
            arr[i], arr[j] = arr[j], arr[i]
            i += 1
            j -= 1
    _hoare_quicksort(arr, lo, j)
    _hoare_quicksort(arr, i, hi)

def fast_sort(arr):
    if not arr:
        return []
    arr = list(arr)
    min_val = min(arr)
    max_val = max(arr)
    range_val = max_val - min_val + 1
    if range_val > 10 * len(arr):
        arr_copy = list(arr)
        _merge_sort_inplace(arr_copy, 0, len(arr_copy))
        return arr_copy
    counts = [0] * range_val
    for x in arr:
        counts[x - min_val] += 1
    result = []
    for i, c in enumerate(counts):
        if c > 0:
            result.extend([i + min_val] * c)
    return result

def _merge_sort_inplace(arr, start, end):
    if end - start <= 1:
        return
    mid = (start + end) // 2
    _merge_sort_inplace(arr, start, mid)
    _merge_sort_inplace(arr, mid, end)
    merged = []
    i, j = start, mid
    while i < mid and j < end:
        if arr[i] <= arr[j]:
            merged.append(arr[i])
            i += 1
        else:
            merged.append(arr[j])
            j += 1
    while i < mid:
        merged.append(arr[i])
        i += 1
    while j < end:
        merged.append(arr[j])
        j += 1
    arr[start:end] = merged

def fast_sort(arr):
