def _introsort(arr, lo, hi, depth_limit):
    if hi - lo < 16:
        _insertion_sort(arr, lo, hi)
        return
    if depth_limit == 0:
        _heapsort_partial(arr, lo, hi)
        return
    mid = (lo + hi) // 2
    if arr[mid] < arr[lo]:
        arr[lo], arr[mid] = arr[mid], arr[lo]
    if arr[hi] < arr[lo]:
        arr[lo], arr[hi] = arr[hi], arr[lo]
    if arr[hi] < arr[mid]:
        arr[mid], arr[hi] = arr[hi], arr[mid]
    arr[mid], arr[hi - 1] = arr[hi - 1], arr[mid]
    pivot = arr[hi - 1]
    i, j = lo, hi - 1
    while True:
        i += 1
        while arr[i] < pivot:
            i += 1
        j -= 1
        while arr[j] > pivot:
            j -= 1
        if i >= j:
            break
        arr[i], arr[j] = arr[j], arr[i]
    arr[i], arr[hi - 1] = arr[hi - 1], arr[i]
    _introsort(arr, lo, i - 1, depth_limit - 1)
    _introsort(arr, i + 1, hi, depth_limit - 1)

def _insertion_sort(arr, lo, hi):
    for i in range(lo + 1, hi + 1):
        key = arr[i]
        j = i - 1
        while j >= lo and arr[j] > key:
            arr[j + 1] = arr[j]
            j -= 1
        arr[j + 1] = key

def _heapsort_partial(arr, lo, hi):
    n = hi - lo + 1
    for i in range(n // 2 - 1, -1, -1):
        _sift(arr, i, n, lo)
    for i in range(n - 1, 0, -1):
        arr[lo], arr[lo + i] = arr[lo + i], arr[lo]
        _sift(arr, 0, i, lo)

def _sift(arr, i, n, offset):
    while True:
        child = 2 * i + 1
        if child >= n:
            break
        if child + 1 < n and arr[offset + child] < arr[offset + child + 1]:
            child += 1
        if arr[offset + i] < arr[offset + child]:
            arr[offset + i], arr[offset + child] = arr[offset + child], arr[offset + i]
            i = child
        else:
            break

