def _dual_pivot_qs(arr, lo, hi):
    if lo >= hi:
        return
    if arr[lo] > arr[hi]:
        arr[lo], arr[hi] = arr[hi], arr[lo]
    p = arr[lo]
    q = arr[hi]
    lt = lo + 1
    gt = hi - 1
    k = lt
    while k <= gt:
        if arr[k] < p:
            arr[k], arr[lt] = arr[lt], arr[k]
            lt += 1
        elif arr[k] > q:
            while arr[gt] > q and k < gt:
                gt -= 1
            arr[k], arr[gt] = arr[gt], arr[k]
            gt -= 1
            if arr[k] < p:
                arr[k], arr[lt] = arr[lt], arr[k]
                lt += 1
        k += 1
    lt -= 1
    gt += 1
    arr[lo], arr[lt] = arr[lt], arr[lo]
    arr[hi], arr[gt] = arr[gt], arr[hi]
    _dual_pivot_qs(arr, lo, lt - 1)
    _dual_pivot_qs(arr, lt + 1, gt - 1)
    _dual_pivot_qs(arr, gt + 1, hi)
